// extract_mvs.c - استخراج motion vectors من فيديو مضغوط
#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    const char *filename = argc > 1 ? argv[1] : "input.mp4";
    AVFormatContext *fmt_ctx = NULL;
    AVCodecContext *codec_ctx = NULL;
    AVFrame *frame = av_frame_alloc();
    AVPacket *pkt = av_packet_alloc();

    avformat_open_input(&fmt_ctx, filename, NULL, NULL);
    avformat_find_stream_info(fmt_ctx, NULL);

    int stream_idx = av_find_best_stream(fmt_ctx, AVMEDIA_TYPE_VIDEO, -1, -1, 0, NULL);
    const AVCodec *codec = avcodec_find_decoder(fmt_ctx->streams[stream_idx]->codecpar->codec_id);
    codec_ctx = avcodec_alloc_context3(codec);
    avcodec_parameters_to_context(codec_ctx, fmt_ctx->streams[stream_idx]->codecpar);
    avcodec_open2(codec_ctx, codec, NULL);

    // فحص ما إذا كان الـ codec يدعم motion vectors
    if (!(codec_ctx->export_side_data & AV_CODEC_EXPORT_DATA_MVS)) {
        printf("هذا الـ codec لا يدعم استخراج motion vectors\n");
        return 0;
    }

    // فك الترميز واستخراج MVs
    while (av_read_frame(fmt_ctx, pkt) >= 0) {
        if (pkt->pkt_side_data) {
            printf("MV packet: size=%d\n", pkt->pkt_side_data->size);
        }
        if (pkt->stream_index == stream_idx) {
            avcodec_send_packet(codec_ctx, pkt);
            while (avcodec_receive_frame(codec_ctx, frame) >= 0) {
                if (frame->side_data) {
                    const AVFrameSideData *sd = frame->side_data;
                    for (int i = 0; i < sd->nb_side_data; i++) {
                        printf("  MV type=%d size=%d\n", sd->type, sd->size);
                    }
                }
            }
        }
        av_packet_unref(pkt);
    }

    av_frame_free(&frame);
    av_packet_free(&pkt);
    avcodec_free_context(&codec_ctx);
    avformat_close_input(&fmt_ctx);
    return 0;
}

